1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G processing fee for an empty item list", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("returns base premium plus fee for a single sword (100 + 5 = 105)");
14	    it.todo("returns base premium plus fee for a single amulet (60 + 5 = 65)");
15	    it.todo("returns base premium plus fee for a single staff (80 + 5 = 85)");
16	    it.todo("returns base premium plus fee for a single potion (40 + 5 = 45)");
17	  });
18	
19	  describe("Quote - components", () => {
20	    it.todo("returns 25G base premium per component (2 runes = 50 + 5 = 55)");
21	    it.todo("applies block discount for exactly 3 alike components (3 runes = 60 + 5 = 65)");
22	    it.todo("does not apply block for 4 alike components (4 runes = 100 + 5 = 105)");
23	    it.todo("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75 + 5 = 80)");
24	    it.todo("applies separate blocks for 3 runes and 3 moonstones (120 + 5 = 125)");
25	    it.todo("calculates 7 alike components without block (7 runes = 175 + 5 = 180)");
26	  });
27	
28	  describe("Quote - item-specific modifiers", () => {
29	    it.todo("adds 50% cursed surcharge to the cursed item base premium");
30	    it.todo("adds 30% high-enchantment surcharge for enchantment level 5");
31	    it.todo("adds both cursed and high-enchantment surcharges when both apply");
32	    it.todo("does not add high-enchantment surcharge for enchantment level 4");
33	  });
34	
35	  describe("Quote - policy-wide modifiers", () => {
36	    it.todo("adds 10% first insurance surcharge to policy base premium");
37	    it.todo("applies 20% loyalty discount for customer with 2+ years");
38	    it.todo("applies 15% follow-up discount on second quote in scenario");
39	  });
40	
41	  describe("Quote - modifier stacking on multi-item policy", () => {
42	    it.todo("applies cursed surcharge only to the cursed item, not the whole policy");
43	    it.todo("sums item base premiums then applies policy-wide modifiers");
44	  });
45	
46	  describe("Quote - rounding", () => {
47	    it.todo("rounds premium up in MHPCO favor");
48	  });
49	
50	  describe("Quote - integration", () => {
51	    it.todo("newcomer with cursed sword: 0 years, first contract, cursed steel sword ench 3 = 165G");
52	    it.todo("long-standing customer second contract: 3 years, 2nd quote, cursed steel sword ench 7 = 160G");
53	  });
54	
55	  describe("Claim - standard reimbursement", () => {
56	    it.todo("reimburses damage minus 100G deductible for a regular item");
57	    it.todo("reimburses damage to a component minus 100G deductible");
58	  });
59	
60	  describe("Claim - special clauses", () => {
61	    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
62	    it.todo("fully reimburses dragon material items, then deductible");
63	    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
64	    it.todo("fully reimburses dragon material with enchantment < 8, then deductible");
65	  });
66	
67	  describe("Claim - cap", () => {
68	    it.todo("caps total payout at 2x insurance sum");
69	    it.todo("tracks remaining cap across multiple claims on the same policy");
70	  });
71	
72	  describe("Claim - multiple items", () => {
73	    it.todo("applies deductible separately per damaged item in a single event");
74	    it.todo("handles two items of the same type in a policy");
75	  });
76	
77	  describe("Claim - payout rounding", () => {
78	    it.todo("rounds payout down in MHPCO favor");
79	  });
80	
81	  describe("Validation", () => {
82	    it.todo("rejects unknown item type in quote with error");
83	    it.todo("rejects claim referencing item not in policy with error");
84	    it.todo("rejects claim with more damage entries than policy covers for a type");
85	    it.todo("rejects claim with negative damage amount");
86	  });
87	});
